/**
 * Matchup Report fixture data — the signature scouting-packet page of the
 * scouting-report identity (per decision [133]). Used by the Matchup Report at
 * /players/:id while the real player → pitch-mix / spray / calibration plumbing
 * is offline.
 *
 * Five batter-vs-pitcher symmetric pairings are hard-coded so any player route
 * (`/players/judge_aaron`, `/players/skubal_tarik`, etc.) lands on a
 * fully-populated, visually-credible report. Unknown ids fall back to
 * Judge → Skubal.
 *
 * Density grids (pitch-location heatmaps + spray-chart zones) are generated by
 * a small 2-D Gaussian helper {@link makeGrid} so the bumps line up with the
 * documented peak locations in spec §11 (FF top-of-zone, SL low-arm-side,
 * CB low-glove-side, CH down-arm-side). Outputs are normalized to [0, 1] so
 * the heatmap component can rescale linearly without per-grid bookkeeping.
 *
 * All numbers are plausible MLB-range values (PA, xwOBA, K%, etc.) but are
 * NOT real data — clearly fictionalised for the redesign demo. The shapes
 * match the eventual API contracts so the page swap from fixture → live data
 * later is component-internal only.
 */

import type { MetricMeta } from "../design/cellColor";

// ── Types (spec §11) ─────────────────────────────────────────────────────────

export type Hand = "L" | "R" | "S";

export type Grade = {
  /** Display label, e.g. "Power", "Contact". */
  label: string;
  /** 20–80 scouting scale; null = no grade. */
  value: number | null;
};

export type ScoutingPlayer = {
  /** Slug id used in URLs (e.g. "judge_aaron"). */
  id: string;
  /** Display name, "First Last". */
  name: string;
  /** Position, e.g. "RF", "SP". */
  position: string;
  /** Bats / throws hand string, e.g. "R/R" or "L/L". */
  hand: string;
  /** Jersey number as a string for tabular alignment. */
  jersey: string;
  /** Team abbreviation, e.g. "NYY". */
  team: string;
  /** Age. */
  age: number;
  /** Listed height. */
  height: string;
  /** Listed weight in lbs. */
  weight: number;
  /** Two- or three-line headline summary above the grades. */
  summary: string;
  /** Ordered list of grade rows. */
  grades: Grade[];
};

/** One row in the pitcher pitch-mix StatTable. */
export type PitchMixRow = {
  /** "FF", "SL", "CB", "CH", "SI", "FC". */
  code: string;
  /** Display name, e.g. "Four-seam". */
  name: string;
  /** Usage %, 0..1. */
  usage: number;
  /** Average velo, mph. */
  velo: number;
  /** Whiff rate vs the batter's hand, 0..1. */
  whiff: number;
  /** xwOBA against, MLB-range. */
  xwoba: number;
  /** Put-away rate (K's / 2-strike), 0..1. */
  putaway: number;
  /** Location density grid, row-major, [0..1]. 12×12. */
  locationGrid: number[][];
};

/** One row in the batter splits StatTable. */
export type SplitRow = {
  /** Split label, e.g. "vs LHP", "vs RHP", "Bases empty". */
  split: string;
  pa: number;
  avg: number;
  obp: number;
  slg: number;
  iso: number;
  xwoba: number;
  k: number;
  bb: number;
};

/** One spray-chart zone summary. */
export type SprayZone = {
  /** Zone id, e.g. "LF-pull", "CF", "RF-oppo". */
  id: string;
  /** Display label. */
  label: string;
  /** Number of batted balls landing here. */
  count: number;
  /** Density 0..1 — used for the cell tint AND a numeric annotation. */
  density: number;
};

/** One recent prediction row. */
export type MatchupPrediction = {
  /** ISO-8601 instant. */
  when: string;
  /** What the model predicted, free-form ("Single", "K-swinging", etc.). */
  predicted: string;
  /** Model probability for the predicted class, 0..1. */
  prob: number;
  /** Observed outcome (free-form). */
  actual: string;
  /** Whether predicted matched actual. */
  agreed: boolean;
};

/** Calibration bin for the reliability diagram. */
export type CalibrationBin = {
  binStart: number;
  binEnd: number;
  predicted: number;
  actual: number;
  n: number;
};

/** A fully resolved Matchup Report (right-side player + opposing-side player). */
export type MatchupReport = {
  /** The player whose route we landed on. */
  primary: ScoutingPlayer;
  /** The opposing-side player. */
  opponent: ScoutingPlayer;
  /** Pitch-mix rows belong to whichever side is the pitcher. */
  pitcherMix: PitchMixRow[];
  /** Splits rows belong to whichever side is the batter. */
  batterSplits: SplitRow[];
  /** Spray chart zones for the batter. */
  spray: SprayZone[];
  /** Recent matchup-context predictions. */
  predictions: MatchupPrediction[];
  /** Calibration bins for the pitch-outcome model on this matchup. */
  calibration: CalibrationBin[];
  /** Free-form key-notes paragraphs (≤ 3). */
  keyNotes: string[];
  /** Headline date / game context. */
  context: string;
};

