// ── Gaussian density helper ──────────────────────────────────────────────────

const GRID_SIZE = 12;

/**
 * Generate a 12×12 density grid with a 2-D Gaussian bump centered at
 * (peakRow, peakCol). Output values are normalized so the grid's maximum is
 * exactly 1.0 and the minimum is ≥ 0.0 (no negatives, no NaNs).
 *
 * Sigma is in grid-cell units. Sigma 1.5–2.0 reads as a focused pitch
 * tendency; sigma 3.0+ reads as a wider area.
 *
 * Used for both pitch-location heatmaps (peak = the pitcher's pitch's
 * preferred zone) and spray-chart density (peak = the batter's preferred
 * sector, expressed as a grid coordinate that the SprayChart projects onto
 * the field outline).
 */
export function makeGrid(
  peakRow: number,
  peakCol: number,
  sigma: number,
): number[][] {
  const grid: number[][] = [];
  let max = 0;
  for (let r = 0; r < GRID_SIZE; r++) {
    const row: number[] = [];
    for (let c = 0; c < GRID_SIZE; c++) {
      const dr = r - peakRow;
      const dc = c - peakCol;
      const val = Math.exp(-(dr * dr + dc * dc) / (2 * sigma * sigma));
      row.push(val);
      if (val > max) max = val;
    }
    grid.push(row);
  }
  // Normalize so the global max is 1.0.
  if (max > 0) {
    for (let r = 0; r < GRID_SIZE; r++) {
      for (let c = 0; c < GRID_SIZE; c++) {
        grid[r][c] = grid[r][c] / max;
      }
    }
  }
  return grid;
}

