// ── Pairings + lookup ────────────────────────────────────────────────────────

/**
 * Symmetric matchup graph. Keyed by either side's id — looking up `judge_aaron`
 * returns the Judge → Skubal pairing; looking up `skubal_tarik` returns the
 * same pairing with `primary` flipped.
 */
const PAIRINGS: Array<[string, string]> = [
  ["judge_aaron", "skubal_tarik"],
  ["trout_mike", "cole_gerrit"],
  ["soto_juan", "skubal_tarik"],
  ["ohtani_shohei", "cole_gerrit"],
  ["bichette_bo", "skenes_paul"],
];

function findPairing(id: string): [string, string] | null {
  for (const [a, b] of PAIRINGS) {
    if (a === id || b === id) return [a, b];
  }
  return null;
}

const KEY_NOTES_JUDGE_SKUBAL: string[] = [
  "Expect Skubal to elevate the four-seamer early — 42 % usage, 97-mph velo, 31 % whiff rate. Judge's 2-strike xwOBA collapses to .302 vs his .452 vs LHP overall, so the first-pitch heater is the at-bat.",
  "Slider is the put-away pitch — low-arm-side, 41 % whiff, 33 % put-away rate. Judge's pull-side authority means a hung slider middle-in is the homer-risk corridor.",
  "Calibration on this matchup is honest (ECE ≈ 0.012, n = 1469). Probabilities above 0.45 have been mildly under-confident — read close calls in Judge's favor at the high end.",
];

const KEY_NOTES_GENERIC: string[] = [
  "Pitcher leans on the primary fastball early; secondary breaking pitch is the put-away. Watch the first-pitch zone tendency for the at-bat plan.",
  "Batter splits favor the matchup hand; pull-side authority is the dominant homer-risk corridor.",
  "Calibration on this matchup is broadly trustworthy (ECE < 0.02, n > 1k). Probabilities in the 0.30–0.55 band have been the most reliable.",
];

/** Build a MatchupReport with the requested player as `primary`. */
export function getDefaultMatchup(playerId: string | undefined): MatchupReport {
  const safeId = playerId && PLAYERS[playerId] ? playerId : "judge_aaron";
  const pairing = findPairing(safeId);
  const [batterId, pitcherId] = pairing ?? ["judge_aaron", "skubal_tarik"];
  const batter = PLAYERS[batterId];
  const pitcher = PLAYERS[pitcherId];
  const primary = safeId === pitcherId ? pitcher : batter;
  const opponent = primary.id === batter.id ? pitcher : batter;

  const isJudgeSkubal =
    (batterId === "judge_aaron" && pitcherId === "skubal_tarik") ||
    (pitcherId === "judge_aaron" && batterId === "skubal_tarik");

  return {
    primary,
    opponent,
    pitcherMix: PITCHER_MIX[pitcherId] ?? SKUBAL_MIX,
    batterSplits: BATTER_SPLITS[batterId] ?? JUDGE_SPLITS,
    spray: BATTER_SPRAY[batterId] ?? JUDGE_SPRAY,
    predictions: isJudgeSkubal ? RECENT_JUDGE_SKUBAL : GENERIC_RECENT,
    calibration: JUDGE_CALIBRATION,
    keyNotes: isJudgeSkubal ? KEY_NOTES_JUDGE_SKUBAL : KEY_NOTES_GENERIC,
    context: isJudgeSkubal
      ? "NYY @ DET · Wed May 27, 2026 · 7:10 PM ET · Comerica Park"
      : `${batter.team} vs ${pitcher.team} · 2026 season aggregate`,
  };
}
